// OAuth 2.0 client for our web application's authentication system
class OAuthClient {
  constructor() {
    this.accessToken = null;
    this.refreshToken = null;
  }

  // Get the current access token from localStorage
  getAccessToken() {
    return localStorage.getItem('accessToken');
  }

  // Set the current access token in localStorage
  setAccessToken(token) {
    localStorage.setItem('accessToken', token);
  }

  // Get the current refresh token from localStorage
  getRefreshToken() {
    return localStorage.getItem('refreshToken');
  }

  // Set the current refresh token in localStorage
  setRefreshToken(token) {
    localStorage.setItem('refreshToken', token);
  }

  // Check if the access token is expired and needs to be refreshed
  checkAccessTokenExpiry() {
    const now = Date.now();
    const expiresAt = this.getAccessToken().expires_at;
    return now >= expiresAt;
  }

  // Refresh the access token using the refresh token
  async refreshAccessToken() {
    const url = 'https://example.com/oauth/token';
    const params = new URLSearchParams();
    params.append('grant_type', 'refresh_token');
    params.append('client_id', 'your-client-id');
    params.append('client_secret', 'your-client-secret');
    params.append('refresh_token', this.getRefreshToken());

    const response = await fetch(url, { method: 'POST', body: params });
    const data = await response.json();

    if (data.error) {
      throw new Error(`Error refreshing access token: ${data.error}`);
    }

    this.setAccessToken(data.access_token);
  }

  // Get the current access token, refreshing it if necessary
  async getCurrentAccessToken() {
    const accessToken = this.getAccessToken();
    if (!accessToken || this.checkAccessTokenExpiry()) {
      await this.refreshAccessToken();
    }
    return this.getAccessToken();
  }
}